namespace UniversityCourseCatalog.Models;

public class Department
{
    public int Id { get; set; }
    public string Code { get; set; } = string.Empty;
    public string Name { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}

namespace UniversityCourseCatalog.Models;

public class Course
{
    public int Id { get; set; }
    public string CourseCode { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Credits { get; set; }
    public string Schedule { get; set; } = string.Empty;
    public string InstructorName { get; set; } = string.Empty;
    public string InstructorBio { get; set; } = string.Empty;
    public int DepartmentId { get; set; }
    public string DepartmentName { get; set; } = string.Empty;
    public bool IsFeatured { get; set; }
}

using System.ComponentModel.DataAnnotations;

namespace UniversityCourseCatalog.Models;

public class EnrollmentRequest
{
    [Required(ErrorMessage = "Name is required.")]
    [StringLength(100, ErrorMessage = "Name cannot exceed 100 characters.")]
    public string StudentName { get; set; } = string.Empty;

    [Required(ErrorMessage = "Student ID is required.")]
    [RegularExpression(@"^[A-Z]{2}\d{6}$", ErrorMessage = "Student ID must be 2 uppercase letters followed by 6 digits (e.g., CS123456).")]
    public string StudentId { get; set; } = string.Empty;

    [Required(ErrorMessage = "Please select a course.")]
    [Range(1, int.MaxValue, ErrorMessage = "Please select a course.")]
    public int CourseId { get; set; }
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public interface ICatalogService
{
    List<Department> GetDepartments();
    Department? GetDepartment(int id);
    List<Course> GetCourses(string? searchTerm = null, int? departmentId = null);
    List<Course> GetFeaturedCourses();
    Course? GetCourse(int id);
    bool SubmitEnrollmentRequest(EnrollmentRequest request);
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService : ICatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Course> _courses;

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Code = "CS", Name = "Computer Science", Description = "Study of computation, algorithms, and information systems." },
            new() { Id = 2, Code = "MATH", Name = "Mathematics", Description = "Exploration of abstract structures, quantities, and patterns." },
            new() { Id = 3, Code = "ENG", Name = "English", Description = "Literature, writing, and critical analysis of texts." },
            new() { Id = 4, Code = "PHYS", Name = "Physics", Description = "Study of matter, energy, and the fundamental forces of nature." },
            new() { Id = 5, Code = "HIST", Name = "History", Description = "Examination of past events and their impact on the present." }
        };

        _courses = new List<Course>
        {
            new() { Id = 1, CourseCode = "CS101", Title = "Introduction to Programming", Description = "Learn the fundamentals of programming using Python. Topics include variables, control flow, functions, and basic data structures. No prior experience required.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", InstructorName = "Dr. Sarah Chen", InstructorBio = "Dr. Chen holds a PhD in Computer Science from MIT and has 15 years of experience teaching introductory programming. She is passionate about making computing accessible to all students.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = true },
            new() { Id = 2, CourseCode = "CS201", Title = "Data Structures and Algorithms", Description = "Study of fundamental data structures (arrays, linked lists, trees, graphs) and algorithm design techniques. Prerequisites: CS101.", Credits = 4, Schedule = "Tue/Thu 10:30–11:45 AM", InstructorName = "Dr. James Rodriguez", InstructorBio = "Dr. Rodriguez is a specialist in algorithm optimization with publications in top-tier conferences. He previously worked at Google Research.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = true },
            new() { Id = 3, CourseCode = "CS310", Title = "Database Systems", Description = "Principles of database design, SQL, normalization, and transaction management. Students build a complete database application as a semester project.", Credits = 3, Schedule = "Mon/Wed 2:00–3:15 PM", InstructorName = "Prof. Maria Santos", InstructorBio = "Prof. Santos spent a decade in industry at Oracle before transitioning to academia. She brings real-world database engineering experience to the classroom.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = false },
            new() { Id = 4, CourseCode = "MATH101", Title = "Calculus I", Description = "Limits, derivatives, and integrals of single-variable functions. Applications to physics and engineering problems.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", InstructorName = "Dr. Robert Kim", InstructorBio = "Dr. Kim is an award-winning mathematics educator who has authored three textbooks on calculus and real analysis.", DepartmentId = 2, DepartmentName = "Mathematics", IsFeatured = true },
            new() { Id = 5, CourseCode = "MATH250", Title = "Linear Algebra", Description = "Vector spaces, linear transformations, matrices, determinants, and eigenvalues. Essential for advanced mathematics and computer science.", Credits = 3, Schedule = "Tue/Thu 1:00–2:15 PM", InstructorName = "Dr. Emily Watson", InstructorBio = "Dr. Watson's research focuses on applied linear algebra in machine learning. She holds joint appointments in Mathematics and Computer Science.", DepartmentId = 2, DepartmentName = "Mathematics", IsFeatured = false },
            new() { Id = 6, CourseCode = "ENG101", Title = "Composition and Rhetoric", Description = "Develop effective academic writing skills through essay composition, peer review, and revision techniques.", Credits = 3, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", InstructorName = "Prof. David Park", InstructorBio = "Prof. Park is a published author and writing coach who emphasizes clarity and argumentation in student writing.", DepartmentId = 3, DepartmentName = "English", IsFeatured = false },
            new() { Id = 7, CourseCode = "ENG215", Title = "American Literature", Description = "Survey of American literary works from the colonial period to the present, exploring themes of identity, freedom, and social change.", Credits = 3, Schedule = "Tue/Thu 9:00–10:15 AM", InstructorName = "Dr. Angela Morris", InstructorBio = "Dr. Morris specializes in 20th-century American fiction and has published extensively on the works of Toni Morrison and James Baldwin.", DepartmentId = 3, DepartmentName = "English", IsFeatured = true },
            new() { Id = 8, CourseCode = "PHYS101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Includes weekly lab sessions with hands-on experiments.", Credits = 4, Schedule = "Mon/Wed/Fri 1:00–1:50 PM + Thu Lab 3:00–5:00 PM", InstructorName = "Dr. Alan Foster", InstructorBio = "Dr. Foster is an experimental physicist whose research in optics has been funded by the National Science Foundation for over a decade.", DepartmentId = 4, DepartmentName = "Physics", IsFeatured = false },
            new() { Id = 9, CourseCode = "PHYS220", Title = "Electromagnetism", Description = "Electric and magnetic fields, Maxwell's equations, electromagnetic waves, and optics.", Credits = 4, Schedule = "Tue/Thu 11:00 AM–12:15 PM", InstructorName = "Dr. Lisa Chang", InstructorBio = "Dr. Chang is a theoretical physicist with expertise in quantum electrodynamics. She is known for her engaging lecture demonstrations.", DepartmentId = 4, DepartmentName = "Physics", IsFeatured = false },
            new() { Id = 10, CourseCode = "HIST101", Title = "World Civilizations", Description = "A global survey of major civilizations from ancient Mesopotamia through the modern era, examining cultural, political, and economic developments.", Credits = 3, Schedule = "Tue/Thu 2:30–3:45 PM", InstructorName = "Dr. Michael Torres", InstructorBio = "Dr. Torres is a historian of global trade networks and has conducted field research across four continents.", DepartmentId = 5, DepartmentName = "History", IsFeatured = true },
            new() { Id = 11, CourseCode = "HIST305", Title = "The Modern Middle East", Description = "Political, social, and cultural transformations in the Middle East from the Ottoman Empire to the present day.", Credits = 3, Schedule = "Mon/Wed 3:30–4:45 PM", InstructorName = "Dr. Nadia Hassan", InstructorBio = "Dr. Hassan is a Middle East studies scholar with a PhD from Georgetown. Her research focuses on post-colonial state formation.", DepartmentId = 5, DepartmentName = "History", IsFeatured = false },
            new() { Id = 12, CourseCode = "CS405", Title = "Machine Learning", Description = "Supervised and unsupervised learning, neural networks, and practical applications. Students complete a capstone ML project.", Credits = 4, Schedule = "Mon/Wed 4:00–5:15 PM", InstructorName = "Dr. James Rodriguez", InstructorBio = "Dr. Rodriguez is a specialist in algorithm optimization with publications in top-tier conferences. He previously worked at Google Research.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = true }
        };
    }

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetCourses(string? searchTerm = null, int? departmentId = null)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue && departmentId.Value > 0)
        {
            query = query.Where(c => c.DepartmentId == departmentId.Value);
        }

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim().ToLowerInvariant();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.CourseCode.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.InstructorName.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public bool SubmitEnrollmentRequest(EnrollmentRequest request)
    {
        // In a real application, this would persist to a database
        return _courses.Any(c => c.Id == request.CourseId);
    }
}

