@page "/"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject ICatalogService CatalogService

<PageTitle>University Course Catalog</PageTitle>

<h1>University Course Catalog</h1>
<p class="lead">Welcome to the university course catalog. Browse departments, explore courses, and submit enrollment requests.</p>

<h2>Featured Courses</h2>
<div class="row">
    @foreach (var course in _featuredCourses)
    {
        <div class="col-md-4 mb-4">
            <div class="card h-100">
                <div class="card-body">
                    <h5 class="card-title">@course.CourseCode — @course.Title</h5>
                    <p class="card-text text-muted">@course.DepartmentName · @course.Credits credits</p>
                    <p class="card-text">@Truncate(course.Description, 120)</p>
                </div>
                <div class="card-footer">
                    <a href="courses/@course.Id" class="btn btn-primary btn-sm">View Details</a>
                </div>
            </div>
        </div>
    }
</div>

<h2 class="mt-4">Departments</h2>
<div class="row">
    @foreach (var dept in _departments)
    {
        <div class="col-md-4 mb-3">
            <div class="card">
                <div class="card-body">
                    <h5 class="card-title">@dept.Name</h5>
                    <p class="card-text">@dept.Description</p>
                    <a href="courses?departmentId=@dept.Id" class="btn btn-outline-primary btn-sm">Browse Courses</a>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private List<Course> _featuredCourses = new();
    private List<Department> _departments = new();

    protected override void OnInitialized()
    {
        _featuredCourses = CatalogService.GetFeaturedCourses();
        _departments = CatalogService.GetDepartments();
    }

    private static string Truncate(string text, int maxLength) =>
        text.Length <= maxLength ? text : text[..maxLength] + "…";
}

@page "/courses"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject ICatalogService CatalogService
@inject NavigationManager Navigation
@rendermode InteractiveServer

<PageTitle>Browse Courses</PageTitle>

<h1>Browse Courses</h1>

<div class="row mb-4">
    <div class="col-md-6">
        <input type="text" class="form-control" placeholder="Search courses..."
               @bind="SearchTerm" @bind:event="oninput" />
    </div>
    <div class="col-md-4">
        <select class="form-select" @bind="SelectedDepartmentId">
            <option value="0">All Departments</option>
            @foreach (var dept in _departments)
            {
                <option value="@dept.Id">@dept.Name</option>
            }
        </select>
    </div>
</div>

@if (_courses.Any())
{
    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead>
                <tr>
                    <th>Code</th>
                    <th>Title</th>
                    <th>Department</th>
                    <th>Credits</th>
                    <th>Instructor</th>
                    <th></th>
                </tr>
            </thead>
            <tbody>
                @foreach (var course in _courses)
                {
                    <tr>
                        <td>@course.CourseCode</td>
                        <td>@course.Title</td>
                        <td>@course.DepartmentName</td>
                        <td>@course.Credits</td>
                        <td>@course.InstructorName</td>
                        <td><a href="courses/@course.Id" class="btn btn-sm btn-outline-primary">Details</a></td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}
else
{
    <p class="text-muted">No courses match your search criteria.</p>
}

@code {
    [SupplyParameterFromQuery] public int? DepartmentId { get; set; }

    private List<Department> _departments = new();
    private List<Course> _courses = new();

    private string _searchTerm = string.Empty;
    private string SearchTerm
    {
        get => _searchTerm;
        set { _searchTerm = value; LoadCourses(); }
    }

    private int _selectedDepartmentId;
    private int SelectedDepartmentId
    {
        get => _selectedDepartmentId;
        set { _selectedDepartmentId = value; LoadCourses(); }
    }

    protected override void OnInitialized()
    {
        _departments = CatalogService.GetDepartments();
        if (DepartmentId.HasValue)
        {
            _selectedDepartmentId = DepartmentId.Value;
        }
        LoadCourses();
    }

    private void LoadCourses()
    {
        int? deptFilter = _selectedDepartmentId > 0 ? _selectedDepartmentId : null;
        _courses = CatalogService.GetCourses(_searchTerm, deptFilter);
    }
}

@page "/courses/{Id:int}"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject ICatalogService CatalogService

<PageTitle>@(_course?.Title ?? "Course Not Found")</PageTitle>

@if (_course is null)
{
    <h1>Course Not Found</h1>
    <p>The requested course does not exist.</p>
    <a href="courses" class="btn btn-primary">Back to Courses</a>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="courses">Courses</a></li>
            <li class="breadcrumb-item active">@_course.CourseCode</li>
        </ol>
    </nav>

    <h1>@_course.CourseCode — @_course.Title</h1>

    <div class="row mt-4">
        <div class="col-md-8">
            <h2>Description</h2>
            <p>@_course.Description</p>

            <h2 class="mt-4">Schedule</h2>
            <p><strong>@_course.Schedule</strong></p>

            <h2 class="mt-4">Credits</h2>
            <p><span class="badge bg-primary fs-6">@_course.Credits credits</span></p>
        </div>

        <div class="col-md-4">
            <div class="card">
                <div class="card-header">
                    <h5 class="mb-0">Instructor</h5>
                </div>
                <div class="card-body">
                    <h6>@_course.InstructorName</h6>
                    <p class="text-muted">@_course.InstructorBio</p>
                </div>
            </div>

            <div class="mt-3">
                <p><strong>Department:</strong> @_course.DepartmentName</p>
                <a href="enroll?courseId=@_course.Id" class="btn btn-success w-100">Enroll in This Course</a>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }

    private Course? _course;

    protected override void OnInitialized()
    {
        _course = CatalogService.GetCourse(Id);
    }
}

@page "/enroll"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject ICatalogService CatalogService

<PageTitle>Enrollment Request</PageTitle>

<h1>Enrollment Request</h1>
<p>Submit this form to request enrollment in a course. You will receive a confirmation from the registrar's office.</p>

@if (_submitted)
{
    <div class="alert alert-success" role="alert">
        <h4 class="alert-heading">Request Submitted</h4>
        <p>Your enrollment request has been submitted successfully. The registrar's office will process your request and notify you by email.</p>
        <hr>
        <p class="mb-0"><a href="courses">Browse more courses</a> or <a href="enroll" @onclick="Reset">submit another request</a>.</p>
    </div>
}
else
{
    <div class="row">
        <div class="col-md-6">
            <EditForm Model="_request" OnValidSubmit="HandleSubmit" FormName="enrollment">
                <DataAnnotationsValidator />
                <ValidationSummary class="text-danger" />

                <div class="mb-3">
                    <label for="studentName" class="form-label">Full Name</label>
                    <InputText id="studentName" class="form-control" @bind-Value="_request.StudentName" />
                    <ValidationMessage For="() => _request.StudentName" class="text-danger" />
                </div>

                <div class="mb-3">
                    <label for="studentId" class="form-label">Student ID</label>
                    <InputText id="studentId" class="form-control" @bind-Value="_request.StudentId" placeholder="e.g., CS123456" />
                    <ValidationMessage For="() => _request.StudentId" class="text-danger" />
                </div>

                <div class="mb-3">
                    <label for="courseSelect" class="form-label">Course</label>
                    <InputSelect id="courseSelect" class="form-select" @bind-Value="_request.CourseId">
                        <option value="0">— Select a course —</option>
                        @foreach (var course in _courses)
                        {
                            <option value="@course.Id">@course.CourseCode — @course.Title</option>
                        }
                    </InputSelect>
                    <ValidationMessage For="() => _request.CourseId" class="text-danger" />
                </div>

                <button type="submit" class="btn btn-primary">Submit Enrollment Request</button>
            </EditForm>
        </div>
    </div>
}

@code {
    [SupplyParameterFromQuery] public int? CourseId { get; set; }
    [SupplyParameterFromForm] private EnrollmentRequest _request { get; set; } = new();

    private List<Course> _courses = new();
    private bool _submitted;

    protected override void OnInitialized()
    {
        _courses = CatalogService.GetCourses();
        if (CourseId.HasValue && _request.CourseId == 0)
        {
            _request.CourseId = CourseId.Value;
        }
    }

    private void HandleSubmit()
    {
        var success = CatalogService.SubmitEnrollmentRequest(_request);
        if (success)
        {
            _submitted = true;
        }
    }

    private void Reset()
    {
        _request = new EnrollmentRequest();
        _submitted = false;
    }
}

